import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as i,e as r,a,f as t}from"./app-c6cbd5e7.js";const o={},d=a("blockquote",null,[a("p",null,"本文反复修改，已确认无精神垃圾aww")],-1),c=t('<p>有点破防，不过不是因为生病本身或是隔离采取的种种措施，单纯因为像我这种深居简出、生活简单的人，每场流行疾病总能毫不意外的发生，实在让人觉得倒霉而无奈 qaq。</p><h2 id="水痘治疗" tabindex="-1"><a class="header-anchor" href="#水痘治疗" aria-hidden="true">#</a> 水痘治疗</h2><blockquote><p>印象中第一次严重的皮肤病qaq</p></blockquote><ul><li>一定要忍着别挠伤口，否则会一直扩散，（<s>觉得痒的话就用痛苦来解决吧</s>）实在忍不了可以备一些止痒药，不过我个人觉得没多大用，试来试去还是酒精来的爽x</li><li>上药的时候勤一点，医用棉签记得备多一点（华子的猫超好像没有专门的医用棉签🤔），不要来回涂抹式上药，否则会把水痘挠破，也会使组织液外流</li><li>对于不便之处的上药要留意一下，如后背等</li><li>最好上药后用多孔绷带缠着全身（一天大概要换四次药），不过考虑到我在的隔离间挺冷，最好外面套层外套（加衣服外套也行）</li><li>说实话真实的感觉是身上有虫子再爬（如果你不去挠它的话）</li></ul><h2 id="隔离间" tabindex="-1"><a class="header-anchor" href="#隔离间" aria-hidden="true">#</a> 隔离间</h2><ul><li>说实话有点无语，这个隔离间好小又乱，空间也很狭窄，也没有窗户（幽闭警告），其他的就不多吐槽了，qaq</li><li>相关工作人员的态度也多少让人有点谔谔了（不过就之前新冠隔离的经验，这种情况得按闹分配，开始可以先上报，有了默许之后就不用了），主要体现在隔离间虽说打扫消毒过了，不过我进来看还是一层灰和不明的脏东西，只好亲自擦了一遍，消毒大概是没有了，生活物资什么的也是自己搞的，医疗物资啥的好像也没有（指棉签绷带这些），最后还是偷偷跑回寝<br> 室拿的</li><li>隔离间有点小冷 qaq</li><li>唯一的好处是单人间？不过上药的时候很麻，后背上不了一点，给大腿内后侧上药时整个人扭曲了</li></ul><h2 id="隔离生活" tabindex="-1"><a class="header-anchor" href="#隔离生活" aria-hidden="true">#</a> 隔离生活</h2><ul><li>上午从医院弄完事项出来差不多八点三刻，然后整理东西（amz that 隔离间被褥啥的也没有），弄了大噶有一个小时，中间也一一把这周的课都请了假，临近期末也没多少课了（，遗憾的是体育课没善终，qaq</li><li>开始不太学的进去，真服了，水痘是魔法物理双修，有时候真难受一批，看了两个多小时番，后面因为没什么好番重新敲起了键盘（恕我直言键盘比较好控手，免得控制不住去挠），把一些零星的文档码了一点，然后就是写这个日记了，不过总体也没花多少时间，主要代码除了作业外也不想写其他的了，没什么精力去思考和优化</li><li>然后因为这周 ddl 也是巨多，不过大部分也都或多或少开了一点（<s>单纯不想善后x</s>）qaq</li></ul><h2 id="后记" tabindex="-1"><a class="header-anchor" href="#后记" aria-hidden="true">#</a> 后记</h2><ul><li>啊真的好痒，酒精抗性了要</li><li>晚上恢复了点胃口，不过精神上还是没有食欲（</li></ul>',10);function h(s,n){return l(),i("div",null,[d,r(" more "),c])}const q=e(o,[["render",h],["__file","2023-12-27.html.vue"]]);export{q as default};
